// Generate rank map requests for each site
const sites = $input.all();
const requests = [];

for (const site of sites) {
  const s = site.json;
  const keywords = [
    s.primary_keyword || 'tattoo shop',
    `tattoo artist ${s.target_city}`,
    `tattoo shop ${s.target_city} ${s.target_state}`
  ];

  for (const keyword of keywords) {
    requests.push({
      json: {
        site_id: s.site_id,
        domain: s.domain,
        business_name: s.business_name,
        keyword,
        city: s.target_city,
        state: s.target_state
      }
    });
  }
}

return requests;

// Parse Local Falcon API response into rank_maps format
const req = $('Rate Limiter').first().json;
const resp = $json;

// Handle API error
if (resp.error || !resp.grid) {
  return [{ json: { error: true, message: resp.error || 'No grid data', keyword: req.keyword } }];
}

const grid = resp.grid || [];
const flatGrid = Array.isArray(grid[0]) ? grid.flat() : grid;
const size = Math.round(Math.sqrt(flatGrid.length));

// Calculate metrics
const validRanks = flatGrid.filter(r => r !== null && r <= 20);
const top3Count = flatGrid.filter(r => r !== null && r <= 3).length;
const top3Pct = flatGrid.length > 0 ? Math.round((top3Count / flatGrid.length) * 100) : 0;
const avgRank = validRanks.length > 0 ? Math.round((validRanks.reduce((a, b) => a + b, 0) / validRanks.length) * 10) / 10 : null;
const centerIdx = Math.floor(flatGrid.length / 2);
const centerRank = flatGrid[centerIdx] || null;

return [{
  json: {
    site_id: req.site_id,
    keyword: req.keyword,
    scan_date: new Date().toISOString().slice(0, 10),
    source: 'local_falcon',
    grid_size: size,
    radius_km: resp.radius || 8,
    grid_data: flatGrid,
    top_3_pct: top3Pct,
    avg_rank: avgRank,
    center_rank: centerRank
  }
}];

// Log error for debugging
console.log('Rank map API error:', $json.message, 'for keyword:', $json.keyword);
return [$input.first()];
